import { Hono } from 'hono';
import { z } from 'zod';

const app = new Hono();

const NotificationSchema = z.object({
  id: z.string(),
  title: z.string(),
  message: z.string(),
  isRead: z.boolean(),
});

type Notification = z.infer<typeof NotificationSchema>;

app.get('/notifications', async (c) => {
  // Simulate fetching user's notifications from a database
  const notifications: Notification[] = [
    { id: '1', title: 'New Order', message: 'Your order has been shipped.', isRead: false },
    { id: '2', title: 'Product Update', message: 'Check out our new product!', isRead: true },
    { id: '3', title: 'Order Confirmation', message: 'Thank you for your purchase.', isRead: true },
  ];

  // Pagination parameters
  const page = parseInt(c.req.query('page')) || 1;
  const limit = parseInt(c.req.query('limit')) || 10;

  // Unread notifications first
  const sortedNotifications = notifications.sort((a, b) => {
    if (a.isRead && !b.isRead) return 1;
    if (!a.isRead && b.isRead) return -1;
    return 0;
  });

  // Paginate the results
  const startIndex = (page - 1) * limit;
  const endIndex = startIndex + limit;
  const paginatedNotifications = sortedNotifications.slice(startIndex, endIndex);

  return c.json(paginatedNotifications);
});

export default app;

